# Hybrid pipeline: combine classical nlpaug with LLM augmentation
import nlpaug.augmenter.word as naw
import anthropic
import json

client = anthropic.Anthropic()


def classical_augment(text: str, n: int = 3) -> list[str]:
    """Fast synonym-based augmentation (no LLM call needed)."""
    aug = naw.SynonymAug(aug_src="wordnet")
    return aug.augment(text, n=n)


def llm_augment(text: str, label: str, n: int = 2) -> list[str]:
    """Higher-quality LLM-based augmentation for hard examples."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        messages=[{"role": "user", "content":
            f"Generate {n} paraphrases of this {label} text. "
            f"Output JSON array only.\n\nText: {text}"}],
    )
    try:
        return json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        return []


def hybrid_augment(
    examples: list[dict],
    classical_per_example: int = 3,
    llm_per_hard_example: int = 2,
    hard_threshold_len: int = 50,  # treat short texts as harder
) -> list[dict]:
    """
    Strategy: classical augmentation for all examples (cheap),
    LLM augmentation for hard/short examples (higher quality).
    """
    augmented = list(examples)
    for ex in examples:
        # Classical augmentation for all
        for syn in classical_augment(ex["text"], n=classical_per_example):
            augmented.append({"text": syn, "label": ex["label"], "source": "classical"})

        # LLM augmentation for short/hard examples only
        if len(ex["text"]) < hard_threshold_len:
            for llm in llm_augment(ex["text"], ex["label"], n=llm_per_hard_example):
                augmented.append({"text": llm, "label": ex["label"], "source": "llm"})

    return augmented
